<?php declare(strict_types=1); namespace WPShadow\Diagnostics; use WPShadow\Core\Diagnostic_Base; if(!defined('ABSPATH')){exit;} class Diagnostic_Post_Embed_Functionality extends Diagnostic_Base{protected static $slug='post-embed-functionality';protected static $title='Post Embed Functionality';protected static $description='Checks if oEmbed functionality is properly configured';protected static $family='posts';public static function check(){if(!has_filter('oembed_dataparse')){return array('id'=>self::$slug,'title'=>self::$title,'description'=>__('oEmbed functionality is not active. Embedded media from external sources will not display.','wpshadow'),'severity'=>'low','threat_level'=>15,'auto_fixable'=>false,'kb_link'=>'https://wpshadow.com/kb/post-embed-functionality',);}return null;}}
